#include "../include/cell_view.h"
#include "../include/topo_link.h"

#include <string.h>

int step_n(CellGrid *a, const int *b, int c, TopoLink *d) {
    (void)b;
    (void)c;
    if (!a || !d) return -1;

    int n = a->n;

    // Initialize.
    d->n_faces = 0;
    for (int i = 0; i < n; i++) {
        d->parent[i] = a->cells[i].parent;
        d->child0[i] = -1;
        d->child_count[i] = 0;
    }

    // Count children per parent.
    for (int i = 0; i < n; i++) {
        int p = d->parent[i];
        if (p >= 0 && p < n) d->child_count[p]++;
    }

    // Assign contiguous child ranges in index order.
    // For this toy driver the children of a parent are created consecutively,
    // so we can use the first occurrence as child0.
    for (int i = 0; i < n; i++) {
        int p = d->parent[i];
        if (p >= 0 && p < n) {
            if (d->child0[p] < 0) d->child0[p] = i;
        }
    }

    return 0;
}
